import UIKit
import SafariServices

class AppDelegate: UIResponder, UIApplicationDelegate {
    func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        guard let url = userActivity.webpageURL else { return false }
        
        if url.host == "myapp.com" && url.path.hasPrefix("/reset-password") {
            if let token = url.queryItems?.first(where: { $0.name == "token" })?.value {
                navigateToPasswordResetScreen(with: token)
                return true
            }
        }
        
        return false
    }

    func navigateToPasswordResetScreen(with token: String) {
        // Navigate to the password reset screen with the token
        if let resetVC = UIStoryboard(name: "Main", bundle: nil).instantiateViewController(withIdentifier: "PasswordResetViewController") as? PasswordResetViewController {
            resetVC.token = token
            guard let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene, let window = windowScene.windows.first else { return }
            window.rootViewController?.present(resetVC, animated: true, completion: nil)
        }
    }
}

